// // This module implements a 3-bit shift register that captures the input data (d) on the falling edge of the clock (clk) and shifts the stored values towards the output. The least significant bit of the buffer is assigned to the output (q), which effectively means that the register outputs the first data bit that was inputted three clock cycles prior.
module top_module( input clk, input d, output q );reg [2:0] buffer;

always @(posedge clk)
begin
    buffer <= {buffer[1:0], d};
end

assign q = buffer[2];

endmodule
